// 🔐 SECURITY MODULE - Bcrypt Password Validation
// ═══════════════════════════════════════════════════════════════════════════════
// All passwords are stored as bcrypt hashes (Algorithm 2b with 10 rounds)
// Default passwords:
//   - TEAM members: formastudio@123
//   - Clients: cliente@123
// NOTE: In production, this should use bcryptjs.compare() on the server
// For now, using simplified client-side validation
const validatePassword = async (plainPassword, bcryptHash) => {
  try {
    // Load bcryptjs library dynamically if needed
    if(typeof bcryptjs !== 'undefined' && bcryptjs.compare) {
      return await bcryptjs.compare(plainPassword, bcryptHash);
    }
    // Fallback: In production, implement server-side validation
    // For testing, we'll use exact hash matching as temporary solution
    console.warn('[SECURITY] Using fallback password validation - implement bcryptjs.compare() in production');
    return false; // Reject unless using proper bcrypt
  } catch(err) {
    console.error('[SECURITY] Password validation error:', err);
    return false;
  }
};

