class ErrorBoundary extends React.Component {
  constructor(props) { super(props); this.state = { error: null }; }
  static getDerivedStateFromError(e) { return { error: e }; }
  componentDidCatch(e, info) { console.error("APP CRASH:", e, info); }
  render() {
    if (this.state.error) {
      var err = this.state.error;
      return (
        <div style={{minHeight:"100vh",background:"#0D0A06",display:"flex",alignItems:"center",justifyContent:"center",fontFamily:"'Poppins',sans-serif",padding:40,position:"relative",overflow:"hidden"}}>
          <style>{"@import url('https://fonts.googleapis.com/css2?family=Poppins:wght@400;600;700;800&display=swap');"}</style>
          {/* Background glow */}
          <div style={{position:"absolute",top:"30%",left:"50%",transform:"translateX(-50%)",width:600,height:300,background:"radial-gradient(ellipse,rgba(239,68,68,0.12) 0%,transparent 70%)",pointerEvents:"none"}}/>
          <div style={{maxWidth:560,width:"100%",zIndex:1}}>
            {/* Icon */}
            <div style={{textAlign:"center",marginBottom:24}}>
              <div style={{display:"inline-flex",alignItems:"center",justifyContent:"center",width:80,height:80,borderRadius:22,background:"rgba(255,106,0,0.10)",border:"1px solid rgba(255,106,0,0.25)",marginBottom:16,overflow:"hidden",padding:8}}><img src="data:image/png;base64," style={{width:"100%",height:"100%",objectFit:"contain"}}/></div>
              <div style={{fontSize:26,fontWeight:800,color:"#fff",marginBottom:4}}>Algo deu errado</div>
              <div style={{fontSize:14,color:"rgba(255,255,255,0.40)",fontWeight:400}}>O sistema encontrou um erro inesperado</div>
            </div>
            {/* Error card */}
            <div style={{background:"rgba(239,68,68,0.06)",border:"1px solid rgba(239,68,68,0.20)",borderRadius:16,padding:20,marginBottom:16}}>
              <div style={{display:"flex",alignItems:"center",gap:8,marginBottom:10}}>
                <div style={{width:8,height:8,borderRadius:"50%",background:"#EF4444",flexShrink:0}}/>
                <div style={{fontSize:13,fontWeight:700,color:"#EF4444",letterSpacing:"0.05em",textTransform:"uppercase"}}>Erro</div>
              </div>
              <div style={{fontSize:14,color:"#FCA5A5",fontWeight:600,marginBottom:12,fontFamily:"monospace",background:"rgba(0,0,0,0.30)",borderRadius:10,padding:"10px 14px",wordBreak:"break-all"}}>
                {err.toString()}
              </div>
              <details style={{cursor:"pointer"}}>
                <summary style={{fontSize:12,color:"rgba(255,255,255,0.35)",listStyle:"none",userSelect:"none",marginBottom:6}}>▸ Ver detalhes técnicos</summary>
                <div style={{fontSize:11,color:"rgba(255,255,255,0.25)",fontFamily:"monospace",whiteSpace:"pre-wrap",wordBreak:"break-all",maxHeight:140,overflowY:"auto",marginTop:6,lineHeight:1.5}}>
                  {err.stack&&err.stack.slice(0,600)}
                </div>
              </details>
            </div>
            {/* Info box */}
            <div style={{background:"rgba(255,255,255,0.03)",border:"1px solid rgba(255,255,255,0.07)",borderRadius:12,padding:"12px 16px",marginBottom:20,display:"flex",gap:10,alignItems:"flex-start"}}>
              <div style={{fontSize:16,flexShrink:0}}>💡</div>
              <div style={{fontSize:12,color:"rgba(255,255,255,0.40)",lineHeight:1.6}}>Tente recarregar a página. Se o problema persistir, entre em contato com a equipe de suporte com uma captura de tela deste erro.</div>
            </div>
            {/* Button */}
            <button onClick={function(){this.setState({error:null});}.bind(this)} style={{width:"100%",padding:"13px",background:"linear-gradient(135deg,#FF6A00,#FF3D00)",color:"#fff",border:"none",borderTopLeftRadius:14,borderTopRightRadius:0,borderBottomRightRadius:14,borderBottomLeftRadius:0,cursor:"pointer",fontWeight:700,fontSize:15,fontFamily:"'Poppins',sans-serif",letterSpacing:"0.02em"}}>
              ↺ Tentar novamente
            </button>
          </div>
        </div>
      );
    }
    return this.props.children;
  }
}

