// Derive isManager from hierarquia
function deriveIsManager(h){ return h==="administrador"||h==="gestor"; }
// Permission checks
function canDo(user, action) {
  var h = user&&user.hierarquia || "colaborador";
  if(h==="administrador") return true;
  if(action==="delete") return h==="gestor"; // gestores can delete
  if(action==="edit")   return h==="gestor"||h==="colaborador"; // gestores + colaboradores can edit
  if(action==="create") return h!=="visualizador"; // everyone except viewer
  if(action==="viewFinanceiro") return h==="administrador"||h==="gestor";
  return h!=="visualizador";
}

