// ─── Logo Component ──────────────────────────────────────────────
const LOGO_SVG = "data:image/png;base64,";

const LogoMark = ({ size }) => {
  const lg = size === "lg";
  const _lmTheme = useTheme();
  const isLight = _lmTheme === "light";
  // SVG viewBox 29700×21000 (A3 landscape) — maintain ratio
  const h = lg ? 160 : size === "md" ? 140 : 104;
  const w = Math.round(h * 29700 / 21000);
  return (
    <img
      src={isLight ? LOGO_SVG_LIGHT : LOGO_SVG}
      alt="FormaStudio"
      width={w}
      height={h}
      style={{
        display: "block",
        flexShrink: 0,
        objectFit: "contain",
        filter: isLight
          ? "none"
          : lg
            ? `drop-shadow(0 4px 20px rgba(250,76,8,0.40))`
            : `drop-shadow(0 2px 8px rgba(250,76,8,0.25))`,
      }}
    />
  );
}

// ─── Shared UI ────────────────────────────────────────────────────
const GlassBox = ({ children, style, onClick, glow, className }) => {
  style = style || {};
  const [h,setH]=useState(false);
  const _theme = useTheme();
  const isLight = _theme==="light";
  const bgNormal = isLight
    ? (h?"rgba(0,0,0,0.06)":"rgba(255,255,255,0.80)")
    : (h?"linear-gradient(160deg,rgba(255,255,255,0.10),rgba(255,255,255,0.04))":"linear-gradient(160deg,rgba(255,255,255,0.055),rgba(255,255,255,0.015))");
  
  const defaultBorder = isLight
    ? (h?"1px solid rgba(0,0,0,0.18)":"1px solid rgba(0,0,0,0.09)")
    : (h?"1px solid var(--cbord2)":"1px solid var(--cbord)");
  
  const shadow = isLight
    ? `0 2px 16px rgba(0,0,0,0.08)${glow?`,0 0 30px ${glow}`:""}`
    : `0 4px 24px rgba(0,0,0,0.30),0 1px 0 rgba(255,255,255,0.08) inset${glow?`,0 0 30px ${glow}`:""}`;
  
  // Determina a borda - respeita style.border se foi passado
  let borderToApply = defaultBorder;
  if (style.border !== undefined) {
    borderToApply = style.border;
  }
  
  const finalStyle = {
    position:"relative", 
    overflow:"hidden",
    background: bgNormal,
    ...gl,
    border: borderToApply,
    boxShadow: shadow,
    transition:"all 0.25s cubic-bezier(0.34,1.56,0.64,1)",
    cursor: onClick ? "pointer" : "default",
    fontFamily:POP,
    ...style,  // style comes LAST to truly override border if provided
  };
  
  return (
    <div className={"glass-box "+(className||"")} onClick={onClick} onMouseEnter={()=>onClick&&setH(true)} onMouseLeave={()=>setH(false)} style={finalStyle}>
      {!isLight&&<div style={{position:"absolute",top:0,left:"8%",right:"8%",height:1,background:"linear-gradient(90deg,transparent,rgba(255,255,255,0.35),transparent)",pointerEvents:"none"}}/>}
      {children}
    </div>
  );
};

