// ─── Export Utilities ─────────────────────────────────────────────
function exportCSV(rows, headers, filename) {
  var hdr = headers.map(function(h){return '"'+h.label+'"';}).join(',');
  var body = rows.map(function(row){return headers.map(function(h){var v=(row[h.key]||'').toString().replace(/"/g,'""');return '"'+v+'"';}).join(',');});
  var csv = [hdr].concat(body).join('\n');
  var blob = new Blob(['\uFEFF'+csv],{type:'text/csv;charset=utf-8;'});
  var url = URL.createObjectURL(blob); var a = document.createElement('a'); a.href=url; a.download=filename; a.click(); URL.revokeObjectURL(url);
}
function exportPrintWindow(title, tableHtml) {
  var now = new Date().toLocaleString('pt-BR');
  var css = '*{box-sizing:border-box;}body{font-family:Arial,sans-serif;color:#111;background:#fff;padding:28px;font-size:13px;margin:0;}h1{font-size:20px;margin:0 0 4px;}.sub{color:#666;font-size:12px;margin-bottom:22px;}table{width:100%;border-collapse:collapse;margin-top:4px;}th{background:#f3f4f6;font-size:11px;text-transform:uppercase;letter-spacing:.06em;padding:8px 10px;text-align:left;border:1px solid #e5e7eb;}td{padding:8px 10px;border:1px solid #e5e7eb;vertical-align:top;}tr:nth-child(even) td{background:#f9fafb;}.badge{display:inline-block;padding:2px 8px;border-radius:4px;font-size:11px;font-weight:700;color:#fff;}.footer{margin-top:28px;font-size:11px;color:#999;border-top:1px solid #eee;padding-top:12px;display:flex;justify-content:space-between;}.no-print{display:flex;gap:10px;}.btn{padding:8px 18px;border:none;border-radius:7px;font-size:13px;cursor:pointer;font-weight:700;}@media print{.no-print{display:none;}body{padding:10px;}}';
  var html = '<!DOCTYPE html><html><head><meta charset="utf-8"><title>'+title+'</title><style>'+css+'</style></head><body>'
    +'<div style="display:flex;justify-content:space-between;align-items:flex-start;margin-bottom:16px;">'
    +'<div><h1>'+title+'</h1><div class="sub">'+now+'</div></div>'
    +'<div class="no-print">'
    +'<button class="btn" style="background:#ff6a00;color:#fff;" onclick="window.print()">🖨 Imprimir</button>'
    +'<button class="btn" style="background:#f3f4f6;color:#333;" onclick="window.closeOverlay&&window.closeOverlay()">✕ Fechar</button>'
    +'</div></div>'
    +tableHtml
    +'<div class="footer"><span>FormaOS 1.0 Em testes | Copyright © Forma Serviços Digitais LTDA</span><span>'+now+'</span></div>'
    +'</body></html>';
  // Remove any existing overlay
  var existing = document.getElementById('fs-print-overlay');
  if (existing) existing.remove();
  // Create iframe overlay — sem window.open(), sem popup blocker
  var overlay = document.createElement('div');
  overlay.id = 'fs-print-overlay';
  overlay.style.cssText = 'position:fixed;inset:0;z-index:99999;background:rgba(0,0,0,0.75);display:flex;align-items:center;justify-content:center;';
  var iframe = document.createElement('iframe');
  iframe.style.cssText = 'width:min(950px,95vw);height:90vh;border:none;border-radius:12px;background:#fff;box-shadow:0 24px 80px rgba(0,0,0,0.6);';
  // Close overlay on backdrop click
  overlay.addEventListener('click', function(e){ if(e.target===overlay){ overlay.remove(); document.body.style.overflow=''; } });
  document.body.appendChild(overlay);
  document.body.style.overflow = 'hidden';
  // Use Blob URL — avoids CSP/sandbox issues with srcdoc and document.write
  var blob = new Blob([html], {type:'text/html;charset=utf-8'});
  var blobUrl = URL.createObjectURL(blob);
  iframe.onload = function() {
    try { iframe.contentWindow.closeOverlay = function(){ URL.revokeObjectURL(blobUrl); overlay.remove(); document.body.style.overflow=''; }; } catch(e){}
  };
  iframe.src = blobUrl;
  overlay.appendChild(iframe);
}

// ─── Notification Bell ────────────────────────────────────────────
// ─── TopbarBtn ── botão ícone padronizado p/ topbar ─────────────
function TopbarBtn({ icon, label, onClick, badge, active }) {
  var [hov, setHov] = React.useState(false);
  var on = active || hov;
  return (
    <div style={{position:"relative",flexShrink:0}} onMouseEnter={function(){setHov(true);}} onMouseLeave={function(){setHov(false);}}>
      <div onClick={onClick} style={{
        width:34,height:34,borderRadius:10,cursor:"pointer",
        display:"flex",alignItems:"center",justifyContent:"center",
        background:on?"rgba(255,106,0,0.14)":"rgba(255,255,255,0.05)",
        border:on?"1px solid rgba(255,106,0,0.30)":"1px solid var(--cbord)",
        transition:"all 0.15s",fontSize:18,position:"relative",userSelect:"none",
      }}>
        {icon}
        {badge>0&&<span style={{position:"absolute",top:-4,right:-4,minWidth:16,height:16,borderRadius:20,background:OR,color:"var(--ct)",fontSize:10,fontWeight:800,fontFamily:POP,display:"flex",alignItems:"center",justifyContent:"center",padding:"0 4px"}}>{badge>99?"99+":badge}</span>}
      </div>
      {hov&&label&&(
        <div style={{position:"absolute",top:"calc(100% + 7px)",left:"50%",transform:"translateX(-50%)",background:"rgba(13,10,6,0.96)",border:"1px solid var(--cbord2)",borderRadius:8,padding:"4px 9px",fontSize:11,color:"var(--ct)",fontFamily:POP,whiteSpace:"nowrap",pointerEvents:"none",zIndex:9999,fontWeight:600,letterSpacing:"0.02em",boxShadow:"0 4px 14px rgba(0,0,0,0.45)"}}>
          {label}
        </div>
      )}
    </div>
  );
}

function NotifBell({ notifications, userId, onMarkAllRead, onClearAll }) {
  var [open, setOpen] = React.useState(false);
  var ref = React.useRef();
  var mine = (notifications||[]).filter(function(n){return n.toId===userId;});
  var unread = mine.filter(function(n){return !n.read;}).length;
  React.useEffect(function(){
    function outside(e){if(ref.current&&!ref.current.contains(e.target))setOpen(false);}
    document.addEventListener('mousedown',outside); return function(){document.removeEventListener('mousedown',outside);};
  },[]);
  var typeIcon=function(t){return t==='mention'?'💬':t==='demanda'?'📥':t==='post'?'📅':t==='reuniao'?'🗓':t==='captacao'?'🎬':t==='calendario'?'📅':t==='incidente'?'⚠️':'🔔';};
  function ago(ts){var m=Math.round((Date.now()-ts)/60000);return m<1?'agora':m<60?m+'min':Math.round(m/60)+'h';}
  return (
    <div ref={ref} style={{position:'relative',flexShrink:0}}>
      <div onClick={function(){setOpen(function(v){return !v;});if(unread>0)onMarkAllRead();}}
        style={{width:34,height:34,borderRadius:10,cursor:'pointer',display:'flex',alignItems:'center',justifyContent:'center',background:open?'rgba(255,106,0,0.14)':'rgba(255,255,255,0.05)',border:open?'1px solid rgba(255,106,0,0.30)':'1px solid rgba(255,255,255,0.09)',position:'relative',transition:'all 0.15s',fontSize:17,userSelect:'none'}}>
        🔔{unread>0&&<span style={{position:'absolute',top:-4,right:-4,minWidth:16,height:16,borderRadius:20,background:'#E74C3C',color:"var(--ct)",fontSize:10,fontWeight:800,fontFamily:POP,display:'flex',alignItems:'center',justifyContent:'center',padding:'0 4px'}}>{unread>9?'9+':unread}</span>}
      </div>
      {open&&(
        <div style={{position:'absolute',top:42,right:0,width:320,background:'#1e1e1e',border:'1px solid rgba(255,255,255,0.12)',borderRadius:14,boxShadow:'0 12px 40px rgba(0,0,0,0.55)',zIndex:2000,overflow:'hidden'}}>
          <div style={{padding:'11px 16px',borderBottom:'1px solid rgba(255,255,255,0.07)',display:'flex',alignItems:'center',justifyContent:'space-between'}}>
            <div style={{fontSize:13,fontWeight:700,color:"var(--ct)",fontFamily:POP}}>Notificações</div>
            {mine.length>0&&<div onClick={onClearAll} style={{fontSize:11,color:"var(--ct3)",cursor:'pointer',fontFamily:POP}} onMouseEnter={function(e){e.currentTarget.style.color='#E74C3C';}} onMouseLeave={function(e){e.currentTarget.style.color='rgba(255,255,255,0.28)';}}>Limpar tudo</div>}
          </div>
          <div style={{maxHeight:340,overflowY:'auto'}}>
            {mine.length===0&&<div style={{padding:'32px 16px',textAlign:'center',color:"var(--ct3)",fontFamily:POP,fontSize:13}}>Nenhuma notificacao</div>}
            {mine.map(function(n){return(
              <div key={n.id} style={{padding:'11px 16px',borderBottom:'1px solid rgba(255,255,255,0.05)',background:n.read?'transparent':'rgba(255,106,0,0.06)',display:'flex',alignItems:'flex-start',gap:10}}>
                <div style={{fontSize:17,flexShrink:0,marginTop:1}}>{typeIcon(n.type)}</div>
                <div style={{flex:1,minWidth:0}}>
                  <div style={{fontSize:13,color:"var(--ct)",fontFamily:POP,lineHeight:1.4,wordBreak:'break-word'}}>{n.text}</div>
                  <div style={{fontSize:11,color:"var(--ct3)",fontFamily:POP,marginTop:3}}>{n.fromName?'De '+n.fromName+' — ':''}{ago(n.ts)}</div>
                </div>
                {!n.read&&<div style={{width:7,height:7,borderRadius:'50%',background:OR,flexShrink:0,marginTop:5}}/>}
              </div>
            );})}
          </div>
        </div>
      )}
    </div>
  );
}

